glsl.vertex:
varying vec2 vUv;
void main(){
 vUv = uv;
 gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
}

glsl.fragment:
precision mediump float;
varying vec2 vUv;
float hash(vec2 p){ return fract(sin(dot(p, vec2(127.1,311.7))) * 43758.5453123); }
float noise(vec2 p){
 vec2 i = floor(p);
 vec2 f = fract(p);
 vec2 u = f*f*(3.0-2.0*f);
 return mix(mix(hash(i), hash(i+vec2(1.0,0.0)), u.x), mix(hash(i+vec2(0.0,1.0)), hash(i+vec2(1.0,1.0)), u.x), u.y);
}
void main(){
 vec2 uv = vUv;
 vec2 p = uv - 0.5;
 float slowWash = noise(uv * 24.0 + vec2(2.1, 4.7));
 float paperGrain = noise(uv * 120.0 + vec2(9.3, 1.8));
 float dryFiber = noise(vec2(uv.x * 18.0, uv.y * 260.0));
 float speck = step(0.86, noise(uv * 390.0 + vec2(3.0, 11.0)));
 float wash = 0.68 + 0.22 * slowWash + 0.06 * paperGrain;
 float centralLift = 1.0 - smoothstep(0.05, 0.78, length(p));
 vec3 deep = vec3(0.012, 0.110, 0.390);
 vec3 ink = vec3(0.030, 0.180, 0.565);
 vec3 c = mix(deep, ink, wash);
 c += centralLift * vec3(0.010, 0.025, 0.050);
 c += (dryFiber - 0.5) * vec3(0.018, 0.022, 0.020);
 c += speck * vec3(0.020, 0.020, 0.016);
 c = clamp(c, 0.0, 1.0);
 gl_FragColor = vec4(c, 1.0);
}
